import time
from datetime import datetime

class CloudSecurityMonitor:
    def __init__(self):
        self.failed_logins = {}
        self.resource_access = {}
        self.thresholds = {
            'max_failed_logins': 3,
            'suspicious_ips': ['192.168.1.100', '10.0.0.50'],
            'unusual_access_hours': (22, 6)  # 10 PM to 6 AM
        }

    def log_login_attempt(self, user_id, ip_address, success):
        timestamp = datetime.now()

        if not success:
            self.failed_logins[user_id] = self.failed_logins.get(user_id, 0) + 1
            if self.failed_logins[user_id] >= self.thresholds['max_failed_logins']:
                self.trigger_alert(user_id, "Account lockout", f"{self.failed_logins[user_id]} failed attempts")
        else:
            self.failed_logins[user_id] = 0

        # Check for suspicious IP
        if ip_address in self.thresholds['suspicious_ips']:
            self.trigger_alert(user_id, "Suspicious IP", f"Login from blacklisted IP: {ip_address}")

        # Check unusual access time
        current_hour = timestamp.hour
        if self.thresholds['unusual_access_hours'][0] <= current_hour or current_hour < self.thresholds['unusual_access_hours'][1]:
            self.trigger_alert(user_id, "Unusual Access Time", f"Login at {timestamp}")

    def log_resource_access(self, user_id, resource, action):
        key = f"{user_id}:{resource}"
        count = self.resource_access.get(key, 0) + 1
        self.resource_access[key] = count

        if count > 100:  # Unusual frequency
            self.trigger_alert(user_id, "High Frequency Access", f"{count} accesses to {resource}")

    def trigger_alert(self, user_id, alert_type, details):
        print(f"[ALERT] {alert_type} - User: {user_id} - Details: {details}")

# Example usage
monitor = CloudSecurityMonitor()

# Simulate failed login attempts
monitor.log_login_attempt("user1", "192.168.1.1", True)
monitor.log_login_attempt("user1", "192.168.1.1", False)
monitor.log_login_attempt("user1", "192.168.1.1", False)
monitor.log_login_attempt("user1", "192.168.1.1", False)

# Simulate suspicious access
monitor.log_login_attempt("user2", "192.168.1.100", True)

# Simulate high frequency access
for i in range(105):
    monitor.log_resource_access("user3", "customer_db", "read")
